interface PlatformCardProps {
  icon: React.ReactNode;
  name: string;
  script: string;
  color: string;
}

function PlatformCard({ icon, name, script, color }: PlatformCardProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(script);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div
      className="rounded-xl border p-5 transition-all duration-300 hover:scale-[1.02]"
      style={{
        borderColor: "var(--docs-border)",
        background: "var(--docs-code-bg)",
      }}
    >
      <div className="flex items-center gap-3 mb-4">
        <div
          className="p-2 rounded-lg"
          style={{ background: color, color: "#fff" }}
        >
          {icon}
        </div>
        <h3
          className="text-lg font-semibold"
          style={{ color: "var(--docs-heading)" }}
        >
          {name}
        </h3>
      </div>
      <div className="relative">
        <pre
          className="rounded-lg p-4 overflow-x-auto text-[12px] leading-6 font-mono border"
          style={{
            background: "var(--background)",
            borderColor: "var(--docs-border)",
            color: "var(--docs-text)",
          }}
        >
          <code>{script}</code>
        </pre>
        <button
          onClick={handleCopy}
          className="absolute top-2 right-2 p-1.5 rounded-md text-xs font-medium transition-all duration-200 hover:opacity-80"
          style={{
            background: "var(--docs-border)",
            color: "var(--docs-text)",
          }}
          title="Copy to clipboard"
        >
          {copied ? "✓ Copied" : "Copy"}
        </button>
      </div>
    </div>
  );
}

export default function PlatformInstall() {
  const platforms = [
    {
      icon: <WindowsIcon />,
      name: "Windows",
      color: "#0078D4",
      script: `# Download
curl -Lo aether.exe https://github.com/Aether-One/aether/releases/latest/download/aether-win-x64.exe

# Move to a folder in your PATH (e.g. C:\\Users\\<user>\\bin)
move aether.exe C:\\Users\\%USERNAME%\\bin\\aether.exe

# Verify
aether --version`,
    },
    {
      icon: <MacIcon />,
      name: "macOS (Apple Silicon)",
      color: "#555555",
      script: `# Download
curl -Lo aether https://github.com/Aether-One/aether/releases/latest/download/aether-macos-arm64

# Make it executable
chmod +x aether

# Remove quarantine flag (prevents Gatekeeper from blocking the binary)
xattr -d com.apple.quarantine aether 2>/dev/null || true

# Move to PATH
sudo mv aether /usr/local/bin/aether

# Verify
aether --version`,
    },
    {
      icon: <LinuxIcon />,
      name: "Linux",
      color: "#E95420",
      script: `# Download
curl -Lo aether https://github.com/Aether-One/aether/releases/latest/download/aether-linux-x64

# Make it executable
chmod +x aether

# Move to PATH
sudo mv aether /usr/local/bin/aether

# Verify
aether --version`,
    },
  ];

  return (
    <div className="grid gap-5 mt-6">
      {platforms.map((platform) => (
        <PlatformCard key={platform.name} {...platform} />
      ))}
    </div>
  );
}
